#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100000
#define MAX_M 500000
#define MAX_Z 100000000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int X[M], Y[M], Z[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &X[i], &Y[i], &Z[i]);
        }
        int source, sink;
        scanf("%d %d", &source, &sink);
        // Create adjacency list
        int **adj = (int **)malloc(N * sizeof(int*));
        int *count = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            adj[i] = (int *)malloc(2 * M * sizeof(int));
            count[i] = 0;
        }
        for (int i = 0; i < M; i++) {
            adj[X[i] - 1][count[X[i] - 1]++] = Y[i] - 1;
            adj[X[i] - 1][count[X[i] - 1]++] = Z[i];
            adj[Y[i] - 1][count[Y[i] - 1]++] = X[i] - 1;
            adj[Y[i] - 1][count[Y[i] - 1]++] = Z[i];
        }
        // Create dp array
        long long ***dp = (long long ***)malloc(N * sizeof(long long**));
        for (int i = 0; i < N; i++) {
            dp[i] = (long long **)malloc(2 * M * sizeof(long long*));
            for (int j = 0; j < 2 * M; j++) {
                dp[i][j] = (long long *)malloc(3 * sizeof(long long));
                for (int k = 0; k < 3; k++) {
                    dp[i][j][k] = LLONG_MAX;
                }
            }
        }
        // Initialize dp array
        dp[source - 1][0][1] = 0;
        // Iterate over all edges
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < count[j]; k += 2) {
                    int u = adj[j][k];
                    int w = adj[j][k + 1];
                    if (dp[j][k / 2][1] != LLONG_MAX && dp[u][k / 2][0] > dp[j][k / 2][1] + w) {
                        dp[u][k / 2][0] = dp[j][k / 2][1] + w;
                    }
                    if (dp[j][k / 2][0] != LLONG_MAX && dp[u][k / 2][1] > dp[j][k / 2][0] + w) {
                        dp[u][k / 2][1] = dp[j][k / 2][0] + w;
                    }
                }
            }
        }
        // Find shortest walk
        long long min = LLONG_MAX;
        for (int i = 0; i < M; i++) {
            if (dp[sink - 1][i][0] < min) {
                min = dp[sink - 1][i][0];
            }
            if (dp[sink - 1][i][1] < min) {
                min = dp[sink - 1][i][1];
            }
        }
        if (min == LLONG_MAX) {
            printf("No Solution\n");
        } else {
            printf("%lld\n", min);
        }
        // Free memory
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < 2 * M; j++) {
                free(dp[i][j]);
            }
            free(dp[i]);
            free(adj[i]);
        }
        free(adj);
        free(dp);
        free(count);
    }
    return 0;
}

